auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
  int64_t count = fs.get_latest(f_count, obj_id);
  int64_t last_access = fs.get_latest(f_last_access, obj_id);
  int64_t size = fs.get_latest(f_size, obj_id);
  int64_t curr_time = fs.get_latest(f_curr_time);

  double recency = static_cast<double>(curr_time - last_access + 1);
  double frequency = static_cast<double>(count);
  double size_d = static_cast<double>(size);

  bool is_ghost = fs.contains(f_ghost, obj_id);

  if (count == 1) {
    double base_score = 10000.0 / recency;
    double size_penalty = size_d / 2048.0;
    double ghost_bonus = is_ghost ? 50000.0 : 0.0;
    return ghost_bonus + base_score - size_penalty;
  }

  double freq_score = std::log1p(frequency) * 8000.0;
  double recency_score = 8000.0 / recency;
  double freq_recency_product = frequency * 200.0 / recency;

  double size_penalty = size_d / (100.0 + frequency * 50.0);

  double ghost_bonus = is_ghost ? 80000.0 : 0.0;

  return ghost_bonus + freq_score + recency_score + freq_recency_product - size_penalty;
};

