auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
  double curr_time = static_cast<double>(fs.get_latest(f_curr_time));
  double last_access = static_cast<double>(fs.get_latest(f_last_access, obj_id));
  double insertion_time = static_cast<double>(fs.get_latest(f_insertion_time, obj_id));
  double access_count = static_cast<double>(fs.get_latest(f_count, obj_id));
  double size = static_cast<double>(fs.get_latest(f_size, obj_id));

  double age = curr_time - last_access;
  double lifetime = curr_time - insertion_time + 1.0;

  // S3FIFO: kill one-hit wonders with tuned threshold
  if (access_count <= 1.0 && age > 1800.0) {
    return -age * 1.5;
  }

  // Hyperbolic access rate
  double access_rate = access_count / lifetime;

  // GDSF: frequency per byte with log dampening for very large objects
  double size_factor = std::log1p(size / 1000.0);
  double freq_per_byte = access_count / (size_factor + 1.0);

  // Adaptive recency decay
  double recency_score = 1.0 / (1.0 + age / 2800.0);

  // Ghost readmission boost
  double ghost_multiplier = fs.contains(f_ghost, obj_id) ? 3.5 : 1.0;

  // Multi-access proven value
  double proven_multiplier = (access_count >= 2.0) ? 2.2 : 1.0;

  // Frequency momentum: recent high-frequency objects get extra boost
  double freq_bonus = (access_count >= 3.0 && age < 1000.0) ? 1.3 : 1.0;

  // Balanced score: optimize weights for access rate vs freq-per-byte
  double base_score = (access_rate * 2500.0 + freq_per_byte * 550000.0 + std::log1p(access_count) * 120.0);

  double final_score = base_score 
                       * recency_score 
                       * ghost_multiplier 
                       * proven_multiplier
                       * freq_bonus;

  return final_score;
};

