  double curr_time = static_cast<double>(fs.get_latest(f_curr_time));
  double last_access = static_cast<double>(fs.get_latest(f_last_access, obj_id));
  double insertion_time = static_cast<double>(fs.get_latest(f_insertion_time, obj_id));
  double age = curr_time - last_access;
  double lifetime = curr_time - insertion_time;

  double access_count = static_cast<double>(fs.get_latest(f_count, obj_id));
  double size = static_cast<double>(fs.get_latest(f_size, obj_id));

  // Risk-adjusted frequency: dividend yield = accesses per unit time
  double access_rate = (lifetime > 0) ? (access_count / lifetime) : access_count;

  // Momentum: stronger decay for older accesses
  double recency_score = 1.0 / (1.0 + age / 5000.0);

  // Size-adjusted return: favor high frequency with lower size penalty
  double size_penalty = 1000.0 / std::sqrt(size + 1.0);

  // Stop-loss override: readmission is a strong buy signal
  double readmission_multiplier = fs.contains(f_ghost, obj_id) ? 5.0 : 1.0;

  // Sharpe-like ratio: frequency and recency are returns, size is risk
  double risk_adjusted_score = (access_rate * 1000.0 + std::log1p(access_count) * 2.0) 
                                * recency_score 
                                * size_penalty 
                                * readmission_multiplier;

  return risk_adjusted_score;
};

