auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
  int64_t last_access = fs.get_latest(f_last_access, obj_id);
  int64_t curr_time = fs.get_latest(f_curr_time);
  int64_t access_count = fs.get_latest(f_count, obj_id);
  int64_t size = fs.get_latest(f_size, obj_id);
  int64_t insertion_time = fs.get_latest(f_insertion_time, obj_id);

  double recency = static_cast<double>(curr_time - last_access + 1);
  double frequency = static_cast<double>(access_count);
  double age = static_cast<double>(curr_time - insertion_time + 1);
  double size_double = static_cast<double>(size);

  // Adaptive size penalty with threshold
  double size_factor;
  if (size_double > 50000.0) {
    // Very large objects get strong penalty
    size_factor = 3000.0 / (size_double / 10.0);
  } else if (size_double > 10000.0) {
    // Large objects get moderate penalty
    size_factor = 5000.0 / std::sqrt(size_double);
  } else {
    // Small/medium objects get mild penalty
    size_factor = 8000.0 / std::sqrt(size_double + 1.0);
  }

  // Frequency with diminishing returns
  double freq_score = std::pow(1.0 + frequency, 0.7);

  // Access rate: accesses per unit time
  double access_rate = frequency / age;
  double rate_boost = 1.0 + (access_rate * 200.0);

  // Recency with adaptive thresholds
  double recency_score;
  if (recency <= 3.0) {
    recency_score = 100000.0;
  } else if (recency <= 20.0) {
    recency_score = 80000.0 / recency;
  } else if (recency <= 100.0) {
    recency_score = 10000.0 / recency;
  } else {
    recency_score = 800.0 / recency;
  }

  // Ghost boost: strong signal for re-admitted objects
  bool was_evicted = fs.contains(f_ghost, obj_id);
  double ghost_boost = was_evicted ? 200.0 : 1.0;

  // Cold object detection: single access and old
  double cold_penalty = (access_count == 1 && recency > 150.0) ? 0.005 : 1.0;

  // Young frequent objects (rising stars)
  double rising_star = (age < 40.0 && frequency >= 4) ? 5.0 : 1.0;

  // Multi-access recent objects get extra boost
  double recent_active_boost = (recency <= 10.0 && frequency >= 2) ? 3.0 : 1.0;

  // Large stale objects with low frequency: aggressive eviction
  double stale_large_penalty = (size_double > 20000.0 && 
                                 recency > 250.0 && frequency < 4) ? 0.05 : 1.0;

  // Warm-up protection: very new objects get grace period
  double warmup_protection = (age < 5.0 && frequency >= 2) ? 2.0 : 1.0;

  double score = recency_score * freq_score * rate_boost * size_factor * 
                 ghost_boost * cold_penalty * rising_star * recent_active_boost * 
                 stale_large_penalty * warmup_protection;

  return score;
};

