auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
  double last_access = static_cast<double>(fs.get_latest(f_last_access, obj_id));
  double curr_time = static_cast<double>(fs.get_latest(f_curr_time));
  double count = static_cast<double>(fs.get_latest(f_count, obj_id));
  double size = static_cast<double>(fs.get_latest(f_size, obj_id));
  double insertion_time = static_cast<double>(fs.get_latest(f_insertion_time, obj_id));

  double recency = curr_time - last_access + 1.0;
  double age = curr_time - insertion_time + 1.0;

  bool was_evicted = fs.contains(f_ghost, obj_id);

  double freq_rate = count / age;

  double recency_score = 1.0 / recency;
  double freq_score = count * freq_rate;

  double size_factor;
  if (size > 60000.0) {
    size_factor = size / 10000.0;
  } else if (size < 8000.0) {
    size_factor = size / 4000.0;
  } else {
    size_factor = size / 6500.0;
  }

  double value_density = (recency_score + freq_score) / size_factor;

  double base_score;
  if (count == 1) {
    base_score = recency_score * 1.2 + value_density * 0.3;
  } else if (count >= 8) {
    base_score = freq_score * 2.5 + recency_score * 0.8 + value_density * 0.5;
  } else {
    double freq_weight = 0.2 + (count - 1.0) / 7.0 * 1.5;
    base_score = recency_score * (1.5 - freq_weight * 0.4) + freq_score * freq_weight + value_density * 0.3;
  }

  if (was_evicted) {
    base_score *= 20.0;
  }

  if (size < 10000.0 && count >= 2) {
    base_score *= 1.8;
  }

  if (freq_rate > 0.1 && size < 50000.0) {
    base_score *= 1.4;
  }

  return base_score;
};

