auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
    int64_t last_access = fs.get_latest(f_last_access, obj_id);
    int64_t count = fs.get_latest(f_count, obj_id);
    int64_t size = fs.get_latest(f_size, obj_id);
    int64_t insertion_time = fs.get_latest(f_insertion_time, obj_id);
    int64_t curr_time = fs.get_latest(f_curr_time);

    // Check if object was recently evicted and re-admitted (ghost hit)
    bool ghost_hit = fs.contains(f_ghost, obj_id);

    // Recency: how recently was the object accessed (exponential decay)
    int64_t age_since_access = curr_time - last_access;
    double recency_score = std::exp(-static_cast<double>(age_since_access) / 1000.0);

    // Frequency: access count with diminishing returns
    double freq_score = std::log1p(static_cast<double>(count));

    // Time in cache - objects that survived longer with high access are valuable
    int64_t time_in_cache = curr_time - insertion_time + 1;
    double access_rate = static_cast<double>(count) / static_cast<double>(time_in_cache);

    // Size-aware scoring: for byte hit rate, larger objects that are accessed
    // contribute more bytes per hit. But we also want to keep smaller objects
    // if they're accessed frequently (they cost less to store).
    double size_d = static_cast<double>(size);

    // For byte hit rate: value = frequency * size (bytes delivered)
    // But cost = size (cache space used)
    // Efficiency = frequency (accesses per unit cache space, but each access delivers 'size' bytes)
    // So for byte hit rate, we want: (count * size) / size = count, but weighted by recency

    // Large objects that are accessed contribute more bytes, so don't penalize size too much
    // Instead, penalize low-frequency large objects
    double byte_value = freq_score * std::log1p(size_d);

    // Ghost hit bonus: strong signal that object is valuable
    double ghost_bonus = ghost_hit ? 3.0 : 1.0;

    // Combined score emphasizing recency and frequency, with size awareness
    double score = ghost_bonus * (recency_score * 2.0 + access_rate * 10.0 + byte_value * 0.5);

    return score;
};

