auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
  int64_t last_access = fs.get_latest(f_last_access, obj_id);
  int64_t count = fs.get_latest(f_count, obj_id);
  int64_t size = fs.get_latest(f_size, obj_id);
  int64_t curr_time = fs.get_latest(f_curr_time);

  // Normalized recency: primary signal
  double recency = static_cast<double>(last_access) / static_cast<double>(curr_time + 1);

  // Log-scaled frequency: rewards popular objects
  double frequency = std::log1p(static_cast<double>(count));

  // Size penalty relative to population median
  double size_percentile_50 = static_cast<double>(fs.get_percentile(f_size, 0.5));
  double size_ratio = static_cast<double>(size) / (size_percentile_50 + 1.0);
  double size_factor = 1.0 / std::log1p(size_ratio);

  // Slightly boost frequency weight and reduce size_factor weight from parent
  return recency * 1000.0 + frequency * 22.0 + size_factor * 100.0;
};

