auto score_fn = [&](const vulcan::feature_store &fs, int64_t obj_id) -> double {
    int64_t last_access = fs.get_latest(f_last_access, obj_id);
    int64_t insertion_time = fs.get_latest(f_insertion_time, obj_id);
    int64_t access_count = fs.get_latest(f_count, obj_id);
    int64_t size = fs.get_latest(f_size, obj_id);
    int64_t curr_time = fs.get_latest(f_curr_time);

    int64_t recency_gap = curr_time - last_access + 1;
    int64_t age = curr_time - insertion_time + 1;

    // Tiered recency with exponential advantage for very recent accesses
    double recency_score;
    if (recency_gap <= 50) {
        recency_score = 2000.0 / static_cast<double>(recency_gap);  // 2x multiplier for hot objects
    } else if (recency_gap <= 150) {
        recency_score = 1500.0 / pow(static_cast<double>(recency_gap), 0.8);
    } else {
        recency_score = 1000.0 / pow(static_cast<double>(recency_gap), 0.65);
    }

    // Quadruple EWMA: capture patterns at 4 time scales
    double freq_ultra_slow = fs.get_ewma(f_count, obj_id, 0.05);  // baseline popularity
    double freq_slow = fs.get_ewma(f_count, obj_id, 0.2);         // sustained trend
    double freq_medium = fs.get_ewma(f_count, obj_id, 0.5);       // recent pattern
    double freq_fast = fs.get_ewma(f_count, obj_id, 0.8);         // burst/spike

    // Momentum: detect accelerating popularity (positive derivative)
    double momentum = freq_fast - freq_medium;
    double momentum_boost = 1.0;
    if (momentum > 1.0) {
        momentum_boost = 2.5;  // strong acceleration
    } else if (momentum > 0.3) {
        momentum_boost = 1.6;  // moderate acceleration
    }

    // Weighted combination favoring recent patterns but respecting baseline
    double freq_combined = 0.45 * freq_fast + 0.3 * freq_medium + 0.15 * freq_slow + 0.1 * freq_ultra_slow;

    // Access rate with logarithmic age dampening (less harsh than sqrt)
    double log_age = log(1.0 + static_cast<double>(age));
    double access_rate = static_cast<double>(access_count) / log_age;

    // Frequency score with momentum
    double frequency_score = (1.0 + 3.0 * freq_combined) * (1.0 + 28.0 * access_rate) * momentum_boost;

    // Multi-tier popularity with finer gradations
    double popularity_tier = 1.0;
    if (access_count >= 10) {
        popularity_tier = 5.5;
    } else if (access_count >= 6) {
        popularity_tier = 3.8;
    } else if (access_count >= 3) {
        popularity_tier = 2.2;
    } else if (access_count >= 2) {
        popularity_tier = 1.4;
    }

    // Size efficiency: bytes per access (lower is better)
    double bytes_per_access = static_cast<double>(size) / (static_cast<double>(access_count) + 1.0);
    double size_kb = static_cast<double>(size) / 1024.0;

    // Adaptive size penalty based on efficiency
    double size_penalty;
    if (bytes_per_access < 5000.0 && access_rate > 0.1) {
        size_penalty = 0.9;  // highly efficient, minimal penalty
    } else if (access_rate > 0.05) {
        size_penalty = 1.0 / (1.0 + 0.5 * log(1.0 + 0.7 * size_kb));
    } else {
        size_penalty = 1.0 / (1.0 + 1.2 * log(1.0 + size_kb));  // harsher for infrequent
    }

    // Context-aware ghost boosting
    double ghost_multiplier = 1.0;
    if (fs.contains(f_ghost, obj_id)) {
        bool quick_readmit = recency_gap < 100;
        bool was_popular = access_count >= 4;
        bool high_momentum = momentum > 0.5;

        if (quick_readmit && was_popular && high_momentum) {
            ghost_multiplier = 12.0;  // perfect storm: keep at all costs
        } else if (quick_readmit && was_popular) {
            ghost_multiplier = 7.0;
        } else if (quick_readmit && high_momentum) {
            ghost_multiplier = 5.5;
        } else if (was_popular) {
            ghost_multiplier = 4.0;
        } else if (quick_readmit) {
            ghost_multiplier = 3.0;
        } else {
            ghost_multiplier = 2.0;
        }
    }

    // Multi-signal synergy: exponential boost when signals align
    double synergy = 1.0;
    int positive_signals = 0;
    if (recency_gap < 100) positive_signals++;
    if (access_rate > 0.1) positive_signals++;
    if (momentum > 0.2) positive_signals++;
    if (access_count >= 4) positive_signals++;

    if (positive_signals >= 3) {
        synergy = 2.8;  // three or more positive signals
    } else if (positive_signals == 2) {
        synergy = 1.6;
    }

    return recency_score * frequency_score * popularity_tier * size_penalty * ghost_multiplier * synergy;
};

